465	          : `Reasoning summary captured: ${shorten(nextSections[0], 96)}`,
466	        stderrMessage: null,
467	        logTitle: sourceLabel ? `Subagent ${sourceLabel} reasoning summary` : "Reasoning summary",
468	        logBody: nextSections.map((section) => `- ${section}`).join("\n")
469	      });
470	    }
471	    return;
472	  }
473	
474	  if (item.type === "fileChange" && lifecycle === "completed") {
475	    state.fileChanges.push(item);
476	    return;
477	  }
478	
479	  if (item.type === "commandExecution" && lifecycle === "completed") {
480	    state.commandExecutions.push(item);
481	  }
482	}
