484	function applyTurnNotification(state, message) {
485	  switch (message.method) {
486	    case "thread/started":
487	      registerThread(state, message.params.thread.id, {
488	        threadName: message.params.thread.name,
489	        name: message.params.thread.name,
490	        agentNickname: message.params.thread.agentNickname,
491	        agentRole: message.params.thread.agentRole
492	      });
493	      break;
494	    case "thread/name/updated":
495	      registerThread(state, message.params.threadId, {
496	        threadName: message.params.threadName ?? null
497	      });
498	      break;
499	    case "turn/started":
500	      registerThread(state, message.params.threadId);
501	      state.threadTurnIds.set(message.params.threadId, message.params.turn.id);
502	      if ((message.params.threadId ?? null) !== state.threadId) {
503	        state.activeSubagentTurns.add(message.params.threadId);
504	      }
505	      emitProgress(
506	        state.onProgress,
507	        `Turn started (${message.params.turn.id}).`,
508	        "starting",
509	        (message.params.threadId ?? null) === state.threadId
510	          ? {
511	              threadId: message.params.threadId ?? null,
512	              turnId: message.params.turn.id ?? null
513	            }
514	          : {}
515	      );
516	      break;
517	    case "item/started":
518	      recordItem(state, message.params.item, "started", message.params.threadId ?? null);
519	      {
520	        const update = describeStartedItem(state, message.params.item);
521	        emitProgress(state.onProgress, update?.message, update?.phase ?? null);
522	      }
523	      break;
524	    case "item/completed":
525	      recordItem(state, message.params.item, "completed", message.params.threadId ?? null);
526	      {
527	        const update = describeCompletedItem(state, message.params.item);
528	        emitProgress(state.onProgress, update?.message, update?.phase ?? null);
529	      }
530	      break;
531	    case "error":
532	      state.error = message.params.error;
533	      emitProgress(state.onProgress, `Codex error: ${message.params.error.message}`, "failed");
534	      break;
535	    case "turn/completed":
536	      if ((message.params.threadId ?? null) !== state.threadId) {
537	        state.activeSubagentTurns.delete(message.params.threadId);
538	        scheduleInferredCompletion(state);
539	        break;
540	      }
541	      emitProgress(
542	        state.onProgress,
543	        `Turn ${message.params.turn.status === "completed" ? "completed" : message.params.turn.status}.`,
544	        "finalizing"
545	      );
546	      completeTurn(state, message.params.turn);
547	      break;
548	    default:
549	      break;
550	  }
551	}
