553	async function captureTurn(client, threadId, startRequest, options = {}) {
554	  const state = createTurnCaptureState(threadId, options);
555	  const previousHandler = client.notificationHandler;
556	
557	  client.setNotificationHandler((message) => {
558	    if (!state.turnId) {
559	      state.bufferedNotifications.push(message);
560	      return;
561	    }
562	
563	    if (message.method === "thread/started" || message.method === "thread/name/updated") {
564	      applyTurnNotification(state, message);
565	      return;
566	    }
567	
568	    if (!belongsToTurn(state, message)) {
569	        if (previousHandler) {
570	          previousHandler(message);
571	        }
572	        return;
573	    }
574	
575	    applyTurnNotification(state, message);
576	  });
577	
578	  try {
579	    const response = await startRequest();
580	    options.onResponse?.(response, state);
581	    state.turnId = response.turn?.id ?? null;
582	    if (state.turnId) {
583	      state.threadTurnIds.set(state.threadId, state.turnId);
584	    }
585	    for (const message of state.bufferedNotifications) {
586	      if (belongsToTurn(state, message)) {
587	        applyTurnNotification(state, message);
588	      } else {
589	        if (previousHandler) {
590	          previousHandler(message);
591	        }
592	      }
593	    }
594	    state.bufferedNotifications.length = 0;
595	
596	    if (response.turn?.status && response.turn.status !== "inProgress") {
597	      completeTurn(state, response.turn);
598	    }
599	
600	    return await state.completion;
601	  } finally {
602	    clearCompletionTimer(state);
603	    client.setNotificationHandler(previousHandler ?? null);
604	  }
605	}
