import fs from "node:fs";
import path from "node:path";
import test from "node:test";
import assert from "node:assert/strict";

import { makeTempDir, run } from "./helpers.mjs";
import { resolveStateDir } from "../plugins/codex/scripts/lib/state.mjs";

const SCRIPT = path.join(
  path.resolve(
    path.dirname(new URL(import.meta.url).pathname),
    "..",
    "plugins",
    "codex",
    "scripts",
    "codex-companion.mjs"
  )
);

test("task --resume-last should only resume tasks from the current session", () => {
  const workspace = makeTempDir();
  const stateDir = resolveStateDir(workspace);
  const jobsDir = path.join(stateDir, "jobs");
  fs.mkdirSync(jobsDir, { recursive: true });

  // Simulate: another session (sess-other) has a completed task with a threadId
  fs.writeFileSync(
    path.join(stateDir, "state.json"),
    `${JSON.stringify(
      {
        version: 1,
        config: { stopReviewGate: false },
        jobs: [
          {
            id: "task-other-session",
            status: "completed",
            title: "Codex Task",
            jobClass: "task",
            sessionId: "sess-other",
            threadId: "thr_other",
            summary: "Old rescue run from other session",
            updatedAt: "2026-03-24T20:05:00.000Z"
          }
        ]
      },
      null,
      2
    )}\n`,
    "utf8"
  );

  // task-resume-candidate should say available: false for current session
  const candidateResult = run("node", [SCRIPT, "task-resume-candidate", "--json"], {
    cwd: workspace,
    env: {
      ...process.env,
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert.equal(candidateResult.status, 0, candidateResult.stderr);
  const candidatePayload = JSON.parse(candidateResult.stdout);
  assert.equal(candidatePayload.available, false, "task-resume-candidate should say no task available for sess-current");

  // task --resume-last should ALSO fail when there is no task in the current session
  const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
    cwd: workspace,
    env: {
      ...process.env,
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert.equal(resumeResult.status > 0, true, "--resume-last should fail when no task in current session");
  assert.match(
    resumeResult.stderr,
    /No previous Codex task thread was found for this repository/,
    "--resume-last error should match the expected message"
  );
});

test("task --resume-last should not be blocked by a running task from another session", () => {
  const workspace = makeTempDir();
  const stateDir = resolveStateDir(workspace);
  const jobsDir = path.join(stateDir, "jobs");
  fs.mkdirSync(jobsDir, { recursive: true });

  // Simulate: another session (sess-other) has a running task
  // Current session (sess-current) has a completed task
  fs.writeFileSync(
    path.join(stateDir, "state.json"),
    `${JSON.stringify(
      {
        version: 1,
        config: { stopReviewGate: false },
        jobs: [
          {
            id: "task-current-completed",
            status: "completed",
            title: "Codex Task",
            jobClass: "task",
            sessionId: "sess-current",
            threadId: "thr_current",
            summary: "Current session rescue run",
            updatedAt: "2026-03-24T20:10:00.000Z"
          },
          {
            id: "task-other-running",
            status: "running",
            title: "Codex Task",
            jobClass: "task",
            sessionId: "sess-other",
            threadId: "thr_other_running",
            summary: "Running rescue from another session",
            updatedAt: "2026-03-24T20:05:00.000Z"
          }
        ]
      },
      null,
      2
    )}\n`,
    "utf8"
  );

  // task-resume-candidate should return the current session's completed task
  const candidateResult = run("node", [SCRIPT, "task-resume-candidate", "--json"], {
    cwd: workspace,
    env: {
      ...process.env,
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert.equal(candidateResult.status, 0, candidateResult.stderr);
  const candidatePayload = JSON.parse(candidateResult.stdout);
  assert.equal(candidatePayload.available, true, "task-resume-candidate should find current session's task");
  assert.equal(candidatePayload.candidate.threadId, "thr_current");

  // task --resume-last should NOT be blocked by sess-other's running task
  // But since we don't have a real app-server, it'll fail when trying to query the app-server.
  // We just need to verify it gets past the "active task" check without being blocked.
  const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
    cwd: workspace,
    env: {
      ...process.env,
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  // We expect this to fail because there's no real codex app-server available.
  // But the error should NOT be "is still running" (which would mean it's being blocked by sess-other's task).
  assert.equal(resumeResult.status > 0, true);
  assert.equal(
    /is still running/.test(resumeResult.stderr),
    false,
    "Should not be blocked by another session's running task"
  );
});

test("resolveLatestTrackedTaskThread respects session filtering when CODEX_COMPANION_SESSION_ID is set", () => {
  const workspace = makeTempDir();
  const stateDir = resolveStateDir(workspace);
  const jobsDir = path.join(stateDir, "jobs");
  fs.mkdirSync(jobsDir, { recursive: true });

  // Both sessions have completed tasks. sess-other has more recent one.
  fs.writeFileSync(
    path.join(stateDir, "state.json"),
    `${JSON.stringify(
      {
        version: 1,
        config: { stopReviewGate: false },
        jobs: [
          {
            id: "task-other-newer",
            status: "completed",
            title: "Codex Task",
            jobClass: "task",
            sessionId: "sess-other",
            threadId: "thr_other_newer",
            summary: "Newer task from other session",
            updatedAt: "2026-03-24T20:15:00.000Z"
          },
          {
            id: "task-current-older",
            status: "completed",
            title: "Codex Task",
            jobClass: "task",
            sessionId: "sess-current",
            threadId: "thr_current_older",
            summary: "Older task from current session",
            updatedAt: "2026-03-24T20:00:00.000Z"
          }
        ]
      },
      null,
      2
    )}\n`,
    "utf8"
  );

  // task-resume-candidate should prefer the current session's task
  const candidateResult = run("node", [SCRIPT, "task-resume-candidate", "--json"], {
    cwd: workspace,
    env: {
      ...process.env,
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert.equal(candidateResult.status, 0, candidateResult.stderr);
  const candidatePayload = JSON.parse(candidateResult.stdout);
  assert.equal(candidatePayload.available, true);
  assert.equal(candidatePayload.candidate.threadId, "thr_current_older");

  // task --resume-last should also pick the current session's task (will fail at app-server level
  // because there is no real codex, but should NOT pick the other session's thread)
  const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
    cwd: workspace,
    env: {
      ...process.env,
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  // Since there's no real app-server, the thread won't be found. The error should indicate
  // it couldn't find a thread from current session, not that it tried to use the other session's.
  assert.equal(resumeResult.status > 0, true);
  // If the fix is correct, it should fail because it can't find the thread in the app-server (no app-server)
  // Not because it picked thr_other_newer
});

