  path.resolve(
    path.dirname(new URL(import.meta.url).pathname),
    "..",
    "plugins",
    "codex",
    "scripts",
    "codex-companion.mjs"
  )
);

test("task --resume-last fails with proper message when no task exists in current session (sess-other has task)", () => {
  const repo = makeTempDir();
  const binDir = makeTempDir();
  installFakeCodex(binDir);
  initGitRepo(repo);
  fs.writeFileSync(path.join(repo, "README.md"), "hello\n");
  run("git", ["add", "README.md"], { cwd: repo });
  run("git", ["commit", "-m", "init"], { cwd: repo });

  // Pre-populate the state: another session (sess-other) has a completed task.
  const stateDir = resolveStateDir(repo);
  const jobsDir = path.join(stateDir, "jobs");
  fs.mkdirSync(jobsDir, { recursive: true });

  const jobFile = path.join(jobsDir, "task-other-session.json");
  fs.writeFileSync(
    jobFile,
    JSON.stringify(
      {
        id: "task-other-session",
        status: "completed",
        title: "Codex Task",
        jobClass: "task",
        sessionId: "sess-other",
        threadId: "thr_other",
        summary: "Old rescue run from other session"
      },
      null,
      2
    ),
    "utf8"
  );

  fs.writeFileSync(
    path.join(stateDir, "state.json"),
    `${JSON.stringify(
      {
        version: 1,
        config: { stopReviewGate: false },
        jobs: [
          {
            id: "task-other-session",
            status: "completed",
            title: "Codex Task",
            jobClass: "task",
            sessionId: "sess-other",
            threadId: "thr_other",
            summary: "Old rescue run from other session",
            updatedAt: "2026-03-24T20:05:00.000Z"
          }
        ]
      },
      null,
      2
    )}\n`,
    "utf8"
  );

  // task-resume-candidate should say available: false for current session
  const candidateResult = run("node", [SCRIPT, "task-resume-candidate", "--json"], {
    cwd: repo,
    env: {
      ...buildEnv(binDir),
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert.equal(candidateResult.status, 0, candidateResult.stderr);
  const candidatePayload = JSON.parse(candidateResult.stdout);
  assert.equal(candidatePayload.available, false, "task-resume-candidate should say no task available for sess-current");

  // task --resume-last should ALSO fail when there is no task in the current session
  const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
    cwd: repo,
    env: {
      ...buildEnv(binDir),
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert.equal(resumeResult.status > 0, true, "--resume-last should fail when no task in current session");
  assert.match(
    resumeResult.stderr,
    /No previous Codex task thread was found for this repository/,
    "--resume-last error should say no previous task thread found"
  );
});

test("task --resume-last should not be blocked by a running task from another session", () => {
  const repo = makeTempDir();
  const binDir = makeTempDir();
  installFakeCodex(binDir);
  initGitRepo(repo);
  fs.writeFileSync(path.join(repo, "README.md"), "hello\n");
  run("git", ["add", "README.md"], { cwd: repo });
  run("git", ["commit", "-m", "init"], { cwd: repo });

  // First, run a real task to create a thread and a completed task in current session
  const firstRun = run("node", [SCRIPT, "task", "initial task"], {
    cwd: repo,
    env: buildEnv(binDir)
  });
  assert.equal(firstRun.status, 0, firstRun.stderr);

  // Now modify the state: mark that completed task as belonging to sess-current,
  // and add a running task from sess-other
  const stateDir = resolveStateDir(repo);
  const jobsDir = path.join(stateDir, "jobs");
  const stateJson = JSON.parse(fs.readFileSync(path.join(stateDir, "state.json"), "utf8"));

  // Find the completed task and mark it as sess-current
  const completedTask = stateJson.jobs.find((job) => job.jobClass === "task" && job.status === "completed");
  assert.ok(completedTask, "Should have a completed task from the first run");
  completedTask.sessionId = "sess-current";

  // Add a running task from sess-other
  stateJson.jobs.push({
    id: "task-other-running",
    status: "running",
    title: "Codex Task",
    jobClass: "task",
    sessionId: "sess-other",
    threadId: "thr_other_running",
    summary: "Running rescue from another session",
    updatedAt: "2026-03-24T20:05:00.000Z"
  });

  fs.writeFileSync(
    path.join(stateDir, "state.json"),
    `${JSON.stringify(stateJson, null, 2)}\n`,
    "utf8"
  );

  // task-resume-candidate should return the current session's completed task
  const candidateResult = run("node", [SCRIPT, "task-resume-candidate", "--json"], {
    cwd: repo,
    env: {
      ...buildEnv(binDir),
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert.equal(candidateResult.status, 0, candidateResult.stderr);
  const candidatePayload = JSON.parse(candidateResult.stdout);
  assert.equal(candidatePayload.available, true, "task-resume-candidate should find current session's task");

  // task --resume-last should NOT be blocked by sess-other's running task
  // It should successfully try to resume the current session's completed task
  const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
    cwd: repo,
    env: {
      ...buildEnv(binDir),
      CODEX_COMPANION_SESSION_ID: "sess-current"
    }
  });
  assert.equal(resumeResult.status, 0, resumeResult.stderr);
  assert.equal(resumeResult.stdout, "Resumed the prior run.\nFollow-up prompt accepted.\n");
});

test("without CODEX_COMPANION_SESSION_ID, --resume-last falls back to unscoped search", () => {
  const repo = makeTempDir();
  const binDir = makeTempDir();
  installFakeCodex(binDir);
  initGitRepo(repo);
  fs.writeFileSync(path.join(repo, "README.md"), "hello\n");
  run("git", ["add", "README.md"], { cwd: repo });
  run("git", ["commit", "-m", "init"], { cwd: repo });

  // Pre-populate state: sess-other has a completed task
  const stateDir = resolveStateDir(repo);
  const jobsDir = path.join(stateDir, "jobs");
  fs.mkdirSync(jobsDir, { recursive: true });

  fs.writeFileSync(
    path.join(jobsDir, "task-other-session.json"),
    JSON.stringify(
      {
        id: "task-other-session",
        status: "completed",
        title: "Codex Task",
        jobClass: "task",
        sessionId: "sess-other",
        threadId: "thr_other",
        summary: "Old rescue run from other session"
      },
      null,
      2
    ),
    "utf8"
  );

  fs.writeFileSync(
    path.join(stateDir, "state.json"),
    `${JSON.stringify(
      {
        version: 1,
        config: { stopReviewGate: false },
        jobs: [
          {
            id: "task-other-session",
            status: "completed",
            title: "Codex Task",
            jobClass: "task",
            sessionId: "sess-other",
            threadId: "thr_other",
            summary: "Old rescue run from other session",
            updatedAt: "2026-03-24T20:05:00.000Z"
          }
        ]
      },
      null,
      2
    )}\n`,
    "utf8"
  );

  // Without CODEX_COMPANION_SESSION_ID, there's no session filtering,
  // so --resume-last should fall back to findLatestTaskThread (app-server query)
  // This will fail because the fake app-server doesn't have the thread stored
  const resumeResult = run("node", [SCRIPT, "task", "--resume-last", "follow up"], {
    cwd: repo,
    env: buildEnv(binDir)
  });

  // In the no-session case, it should fall through to findLatestTaskThread which queries app-server.
  // The fake app-server has no threads named "Codex Companion Task", so this should fail.
  assert.equal(resumeResult.status > 0, true, "Should fail when no threads found via app-server fallback");
});

test("resolveLatestTrackedTaskThread prefers current session tasks over other session tasks", () => {
  const repo = makeTempDir();
  const binDir = makeTempDir();
  installFakeCodex(binDir);
  initGitRepo(repo);
  fs.writeFileSync(path.join(repo, "README.md"), "hello\n");
  run("git", ["add", "README.md"], { cwd: repo });
  run("git", ["commit", "-m", "init"], { cwd: repo });

  // Run a task to create a thread in the app-server and a completed job
  const firstRun = run("node", [SCRIPT, "task", "initial task"], {
    cwd: repo,
